mapper.select:
SELECT id, supplier_name, contract_type, monthly_supply_kwh, start_date, end_date, rate_per_kwh, monthly_cost_snapshot, status, terminated_at, terminated_by, notes, location_id, created_by, updated_by, created_at, updated_at, is_deleted FROM contracts WHERE is_deleted = 0
AND status = #{status}
AND contract_type = #{contractType}
ORDER BY created_at DESC

SELECT COUNT(*)
FROM contracts
WHERE supplier_name = #{supplierName}
AND status = 'ACTIVE'
AND is_deleted = 0
AND start_date <= #{endDate}
AND end_date >= #{startDate}

    AND id != #{excludeId}

SELECT COALESCE(SUM(monthly_supply_kwh), 0)
FROM contracts
WHERE status = 'ACTIVE'
AND start_date <= #{lastDay}
AND end_date >= #{firstDay}
AND is_deleted = 0
